import{_ as i,o as a,c as n,a3 as s}from"./chunks/framework.CLYqdwvN.js";const p=JSON.parse('{"title":"Update-Prüfung","description":"","frontmatter":{},"headers":[],"relativePath":"de/advanced/update-check.md","filePath":"de/advanced/update-check.md"}'),t={name:"de/advanced/update-check.md"};function r(d,e,o,l,h,c){return a(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="update-prufung" tabindex="-1">Update-Prüfung <a class="header-anchor" href="#update-prufung" aria-label="Permalink to &quot;Update-Prüfung&quot;">​</a></h1><p>amoxide prüft crates.io regelmäßig auf eine neuere Version und gibt einen einzeiligen Hinweis aus, wenn eine verfügbar ist. Die Prüfung ist <strong>nicht blockierend</strong>, <strong>24 Stunden im Cache</strong> und <strong>vollständig abschaltbar</strong>.</p><h2 id="was-du-siehst" tabindex="-1">Was du siehst <a class="header-anchor" href="#was-du-siehst" aria-label="Permalink to &quot;Was du siehst&quot;">​</a></h2><p>Wenn eine neuere Version verfügbar ist, geben die Listing-Befehle (<code>am ls</code>, <code>am la</code>, <code>am profile list</code>) eine einzelne Zeile auf <strong>stderr</strong> nach der Liste aus:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>am: 💡 a new version is available: v0.9.0 -&gt; visit https://github.com/sassman/amoxide-rs/releases</span></span></code></pre></div><p>Wenn du bereits auf der neuesten Version bist, wird nichts ausgegeben.</p><h2 id="so-funktioniert-es" tabindex="-1">So funktioniert es <a class="header-anchor" href="#so-funktioniert-es" aria-label="Permalink to &quot;So funktioniert es&quot;">​</a></h2><ul><li>Beim ersten Aufruf eines Listing-Befehls startet amoxide einen abgekoppelten Hintergrundprozess, der crates.io anfragt. Die Ausgabe von <code>am ls</code> erscheint sofort — du wartest auf nichts.</li><li>Das Ergebnis wird in eine lokale Cache-Datei unter <code>~/.cache/amoxide/update-check.toml</code> geschrieben.</li><li>Folgeaufrufe lesen diesen Cache. Ist er älter als 24 Stunden, wird eine neue Hintergrundprüfung gestartet und das gecachte Ergebnis (falls vorhanden) inzwischen angezeigt.</li><li>Alle Fehler (offline, DNS-Fehler, Timeout, fehlerhafte Antwort) werden lautlos geschluckt. Der Listing-Befehl scheitert nie wegen der Update-Prüfung.</li></ul><p>Da der Hinweis auf stderr geht, funktionieren Skripte, die <code>am ls</code> weiterpipen, unverändert:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mein-alias</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # vom Hinweis nicht betroffen</span></span></code></pre></div><h2 id="prufung-deaktivieren" tabindex="-1">Prüfung deaktivieren <a class="header-anchor" href="#prufung-deaktivieren" aria-label="Permalink to &quot;Prüfung deaktivieren&quot;">​</a></h2><p>Du kannst die Update-Prüfung per <strong>Konfiguration</strong> (einmalig) oder <strong>Umgebungsvariable</strong> (pro Aufruf, ideal für CI) abschalten.</p><h3 id="konfiguration-config-amoxide-config-toml" tabindex="-1">Konfiguration: <code>~/.config/amoxide/config.toml</code> <a class="header-anchor" href="#konfiguration-config-amoxide-config-toml" aria-label="Permalink to &quot;Konfiguration: `~/.config/amoxide/config.toml`&quot;">​</a></h3><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">update</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">check = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><p>Wenn <code>check = false</code> gesetzt ist, finden weder Cache-Lesen noch Hintergrund-Spawn statt. Es wird kein Netzwerkaufruf gemacht und keine Cache-Datei angelegt.</p><h3 id="umgebung-am-no-update-check" tabindex="-1">Umgebung: <code>AM_NO_UPDATE_CHECK</code> <a class="header-anchor" href="#umgebung-am-no-update-check" aria-label="Permalink to &quot;Umgebung: `AM_NO_UPDATE_CHECK`&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">AM_NO_UPDATE_CHECK</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span></span></code></pre></div><p>Setze diese auf einen beliebigen nicht-leeren Wert, um die Prüfung für einen Aufruf zu überspringen. Nützlich in CI-Umgebungen, wo du weder einen Netzwerkaufruf noch eine Konfigurationsänderung möchtest.</p><h2 id="datenschutz" tabindex="-1">Datenschutz <a class="header-anchor" href="#datenschutz" aria-label="Permalink to &quot;Datenschutz&quot;">​</a></h2><p>Die Prüfung sendet eine HTTPS-Anfrage an <code>https://crates.io/api/v1/crates/amoxide</code>. Die einzigen Daten, die dein Gerät verlassen, sind der Crate-Name und der von ureq gesetzte User-Agent. Keine Telemetrie, keine Identifikatoren, keine Version deines lokalen Binarys wird übertragen.</p><h2 id="siehe-auch" tabindex="-1">Siehe auch <a class="header-anchor" href="#siehe-auch" aria-label="Permalink to &quot;Siehe auch&quot;">​</a></h2><ul><li><a href="/_preview/126/de/advanced/config-files">Konfigurationsdateien</a> — vollständige TOML-Referenz</li></ul>',22)])])}const g=i(t,[["render",r]]);export{p as __pageData,g as default};
